@font-face {
  font-family: 'SpecialNumbers';
  src: url('/fonts/special-numbers.woff2') format('woff2');
  unicode-range: U+0-9, U+20-2F, U+3A-40, U+5B-60, U+7B-7E; /* Basic ASCII numbers and common symbols */
  font-weight: 400;
  font-style: normal;
}

@font-face {
  font-family: 'MainBodyFont';
  src: url('/fonts/main-body.woff2') format('woff2');
  unicode-range: U+0020-007E; /* Basic Latin, printable ASCII characters */
  font-weight: 400;
  font-style: normal;
}

h1 {
  font-family: 'SpecialNumbers', sans-serif;
  /* Other heading styles */
}

p {
  font-family: 'MainBodyFont', sans-serif;
  /* Other paragraph styles */
}
